            if (num & (1 << bit)) {
                if (!bitPositions.has(bit)) {
                    bitPositions.set(bit, new Set());
                }
                bitPositions.get(bit).add(i);
            }
        }
    }

    const possibleKs = new Set();

    for (let i = 0; i < n; ++i) {
        let num = nums[i];
        for (let bit = 0; bit < 32; ++bit) {
            if (num & (1 << bit)) {
                const positions = bitPositions.get(bit);
                if (positions) {
                    for (const j of positions) {
                        if (i < j) {
                            const k = num & nums[j];
                            possibleKs.add(k);
                        }
                    }
                }
            }
        }
    }

    for (let k = 1; k <= n; ++k) {
        if (possibleKs.has(k)) {
            return k;
        }
    }

    return 0;
}
